THE CLAIM:
{
 "title": "German billing rules block core PDU value in half the market",
 "narrative": "The model assumes the smart PDU's metering premium sells across all geography. But in Germany, half the modeled geography, meters used to bill tenants per kWh must be legally certified, not just accurate, and this venture is not certified. That certification takes multiple quarters, so the Year-1 reachable share drops to the band floor at 0.45.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "German law requires certified meters whenever billed per kilowatt-hour.",
   "refs": [
    "digest:serviceable-benchmark#c13",
    "ledger:serviceableFactor"
   ]
  },
  {
   "step": "propagation",
   "text": "Colocation operators re-billing tenants are the buyers paying the premium; Germany is half the geography.",
   "refs": [
    "ledger:geo.DE",
    "ledger:seg.colocation",
    "digest:serviceable-benchmark#c4"
   ]
  },
  {
   "step": "propagation",
   "text": "Certification takes multiple quarters, missing Year 1; German billing demand is foreclosed.",
   "refs": [
    "profile:Stage",
    "digest:serviceable-benchmark#c8"
   ]
  },
  {
   "step": "model-impact",
   "text": "The 0.55 factor includes demand it cannot reach; share falls to floor.",
   "refs": [
    "ledger:serviceableFactor",
    "ledger:geo.DE"
   ]
  }
 ],
 "falsifier": "Two German colocation operators or the regulator confirm that PDU metering for tenant re-billing is exempt, or that capacity-tier billing makes certified metering commercially irrelevant.",
 "category": "boundary",
 "evidence": [
  {
   "title": "Is your sub-metering system MID compliant?",
   "sourceType": "industry-report",
   "publisher": "Inteb",
   "date": "2022-03-07",
   "excerpt": "The consumption data from these sub-meters is then used to charge tenants for their personal energy use... all meters used for tenant recharging must comply with MID.",
   "url": "https://weareinteb.co.uk/news/is-your-sub-metering-system-mid-compliant/",
   "attached": true
  },
  {
   "title": "MID Approved Power Metering - EDP Europe",
   "sourceType": "industry-report",
   "publisher": "EDP Europe",
   "date": "2023-10-24",
   "excerpt": "MID ... will stipulate that all meters supplied and installed for private billing must be MID certified. EDP Europe’s MID approved power metering system enables data centre hosting operatives to comply with this new legislation.",
   "url": "https://www.edpeurope.com/products/power-monitoring/power-distribution/intelligent-pdus/mid-approved-power-metering/",
   "attached": true
  },
  {
   "title": "Sector 3: Measuring Instruments Directive (MID) - PTB.de",
   "sourceType": "industry-report",
   "publisher": "PTB",
   "date": null,
   "excerpt": "EU type-examinations according to directive 2014/32/EU module B ... approvals of quality systems according to directive 2014/32/EU modules D, D1 ... Measuring instruments for electrical energy (WG 2.34)",
   "url": "https://www.ptb.de/cms/en/metrological-services/kbs/kbs3.html",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "serviceableFactor",
  "label": "Serviceable share of TAM",
  "kind": "assumption",
  "value": 0.55,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "needs-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.45,
   "high": 0.65
  },
  "funnelActive": true,
  "derivation": {
   "method": "Reachability assumption",
   "expression": "No public SAM/TAM benchmark for B2B hardware exists; EU cert stack (EN 50600, ecodesign 2019/424, CE/TÜV) justifies < 1.0 but doesn't quantify 0.55"
  },
  "provenance": {
   "rationale": "Assumption leaf — channel + regulatory reach; EU certification barriers documented qualitatively only.",
   "promotionPath": "Bottom-up channel-coverage model (named accounts × reachable share) → sourced serviceable %."
  },
  "evidence": [
   {
    "title": "EU ecodesign requirements for servers and data storage (2019/424)",
    "sourceType": "industry-report",
    "publisher": "EUR-Lex",
    "date": "2019",
    "excerpt": "EU ecodesign and certification requirements gate which demand is regulatory-clear for a new entrant — the qualitative basis of the serviceable haircut.",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
